require "array"

module Solution
  class Solver
    def solve(nums : Array(Int64), queries : Array(Array(Int64))) : Array(Int64)
      ans = Array(queries.size)

      for i in 0...queries.size do
        l = queries[i][0].to_int
        r = queries[i][1].to_int
        k = queries[i][2]

        // 1. Identify removed even numbers
        removed_evens = Array(nums[l..r]).select do |n|
          n >= 2 && n % 2 == 0
        end

        // 2. Count removed even numbers
        removed_count = removed_evens.size

        // 3. Find the k-th smallest remaining positive even number
        // The sequence of all positive even numbers is 2, 4, 6, 8, 10, 12, ...
        // The n-th positive even number is 2 * n.

        // We are looking for the m-th even number (2*m) such that it was NOT in removed_evens,
        // and it is the k-th smallest such number.

        // Let N be the target even number: N = 2 * m.
        // The number of even numbers less than or equal to N is m.
        // The number of *removed* even numbers less than or equal to N is count_removed(N).
        // The number of *remaining* even numbers less than or equal to N is m - count_removed(N).

        // We want this count to be exactly k.
        // m - count_removed(2*m) = k

        // Since k is up to 10^9, we can use binary search for m.
        // The target value 2*m will be around 2 * 10^9 + removed_count (which is at most 10^5).
        // A safe upper bound for m is around 2 * 10^9 + 10^5. Let's use 2 * 10^9 + 10^5 + 1.

        low = 1_i64
        // A sufficiently large upper bound for m. Since k <= 10^9, 2*k is a safe initial estimate for the answer, 
        // so m <= k + removed_count. Let's use 2 * 10^9 + 100005.
        high = 2_000_000_000_i64 + 100005_i64 
        result_m = high

        while low <= high
          m = (low + high) / 2
          target_even = 2 * m

          // Count how many removed evens are <= target_even
          count_removed = 0
          for r_even in removed_evens do
            if r_even <= target_even do
              count_removed += 1
            end
          end

          // Remaining count <= target_even is m - count_removed
          remaining_count = m - count_removed

          if remaining_count >= k
            // This value 2*m might be the answer, or the answer is smaller. Try smaller m.
            result_m = m
            high = m - 1
          else
            // Too few remaining evens. Need a larger target.
            low = m + 1
          end
        end

        // The answer is 2 * result_m
        ans[i] = 2 * result_m
      end

      return ans
    end
  end
end
